+/* Operational code block — for multi-line commands / config snippets */
+.sm-scope pre.sm-code-block {
+  background: rgba(0, 0, 0, 0.5);
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  border-radius: 0.75rem;
+  padding: 0.875rem 1.125rem;
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  font-size: 0.8125rem;
+  line-height: 1.65;
+  color: #e2e8f0;
+  overflow-x: auto;
+  margin: 1.25rem 0 1.5rem;
+  -webkit-overflow-scrolling: touch;
+}
+
+.sm-scope pre.sm-code-block code {
+  font-family: inherit;
+  font-size: inherit;
+  color: inherit;
+  background: none;
+  padding: 0;
+  border-radius: 0;
+  white-space: pre;
+  display: block;
+  min-width: max-content;
+}
+
+/* Command-prompt styling: lines prefixed with $ or # get a dim leader */
+.sm-scope .sm-code-block .sm-prompt {
+  color: #64748b;
+  user-select: none;
+  margin-right: 0.5rem;
+}
+
+.sm-scope .sm-code-block .sm-comment {
+  color: #64748b;
+  font-style: italic;
+}
+
+/* Reference tables for troubleshooting, cost breakdowns, stage cheatsheets */
+.sm-scope .sm-table-wrap {
+  margin: 1.5rem 0 2rem;
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  border-radius: 0.75rem;
+  overflow: auto;
+  -webkit-overflow-scrolling: touch;
+  background: rgba(255, 255, 255, 0.01);
+}
+
+.sm-scope table.sm-table {
+  width: 100%;
+  border-collapse: collapse;
+  font-size: 0.875rem;
+  font-family: var(--font-bricolage), var(--font-crimson), system-ui, sans-serif;
+}
+
+.sm-scope table.sm-table th {
+  background: rgba(255, 255, 255, 0.03);
+  color: #67e8f9;
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  font-weight: 600;
+  text-align: left;
+  padding: 0.625rem 0.875rem;
+  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
+  font-size: 0.7rem;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+  white-space: nowrap;
+}
+
+.sm-scope table.sm-table td {
+  padding: 0.7rem 0.875rem;
+  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
+  color: #cbd5e1;
+  vertical-align: top;
+  line-height: 1.5;
+}
+
+.sm-scope table.sm-table tr:last-child td {
+  border-bottom: none;
+}
+
+.sm-scope table.sm-table tr:hover td {
+  background: rgba(255, 255, 255, 0.015);
+}
+
+.sm-scope table.sm-table code,
+.sm-scope table.sm-table .sm-inline-code {
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  color: #67e8f9;
+  background: rgba(6, 182, 212, 0.08);
+  padding: 0.05rem 0.3rem;
+  border-radius: 0.2rem;
+  font-size: 0.82em;
+  white-space: nowrap;
+}
+
+/* Inline TOC near the top of the article */
+.sm-scope .sm-toc {
+  margin: 1.5rem 0 2rem;
+  padding: 1.25rem 1.5rem;
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  border-radius: 1rem;
+  background: rgba(255, 255, 255, 0.02);
+  backdrop-filter: blur(8px);
+}
+
+.sm-scope .sm-toc h3 {
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  font-size: 0.7rem;
+  letter-spacing: 0.22em;
+  text-transform: uppercase;
+  color: #94a3b8;
+  margin-bottom: 0.875rem;
+}
+
+.sm-scope .sm-toc ol {
+  list-style: decimal;
+  margin-left: 1.1rem;
+  font-family: var(--font-bricolage), var(--font-crimson), system-ui, sans-serif;
+  font-size: 0.95rem;
+  column-count: 1;
+  column-gap: 1.5rem;
+}
+
+@media (min-width: 768px) {
+  .sm-scope .sm-toc ol {
+    column-count: 2;
+  }
+}
+
+.sm-scope .sm-toc ol li {
+  break-inside: avoid;
+  margin-bottom: 0.35rem;
+  padding-left: 0.25rem;
+  color: #cbd5e1;
+}
+
+.sm-scope .sm-toc a {
+  color: #cbd5e1;
+  text-decoration: none;
+  transition: color 0.15s;
+  border-bottom: 1px dotted transparent;
+}
+
+.sm-scope .sm-toc a:hover {
+  color: #67e8f9;
+  border-bottom-color: rgba(103, 232, 249, 0.5);
+}
+
+/* Expandable reference block (details/summary) */
+.sm-scope details.sm-details {
+  margin: 1.25rem 0;
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  border-radius: 0.875rem;
+  background: rgba(255, 255, 255, 0.02);
+  overflow: hidden;
+}
+
+.sm-scope details.sm-details > summary {
+  padding: 0.875rem 1.125rem;
+  cursor: pointer;
+  font-family: var(--font-bricolage), var(--font-crimson), system-ui, sans-serif;
+  font-size: 0.95rem;
+  color: #e2e8f0;
+  font-weight: 600;
+  list-style: none;
+  display: flex;
+  align-items: center;
+  gap: 0.5rem;
+  transition: background 0.15s;
+}
+
+.sm-scope details.sm-details > summary::-webkit-details-marker {
+  display: none;
+}
+
+.sm-scope details.sm-details > summary::before {
+  content: "›";
+  display: inline-block;
+  color: #67e8f9;
+  transition: transform 0.15s;
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  font-size: 1rem;
+  flex-shrink: 0;
+}
+
+.sm-scope details.sm-details[open] > summary::before {
+  transform: rotate(90deg);
+}
+
+.sm-scope details.sm-details > summary:hover {
+  background: rgba(255, 255, 255, 0.03);
+}
+
+.sm-scope details.sm-details[open] > summary {
+  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
+}
+
+.sm-scope details.sm-details > .sm-details-body {
+  padding: 1rem 1.125rem 1.25rem;
+}
+
+.sm-scope details.sm-details > .sm-details-body p {
+  font-family: var(--font-bricolage), var(--font-crimson), system-ui, sans-serif !important;
+  font-size: 0.95rem !important;
+  line-height: 1.65 !important;
+  margin-bottom: 0.75rem !important;
+  color: #cbd5e1 !important;
+}
+
+.sm-scope details.sm-details > .sm-details-body p:last-child {
+  margin-bottom: 0 !important;
+}
+
+/* Subsection heading */
+.sm-scope .sm-subheading {
+  font-family: var(--font-bricolage), system-ui, sans-serif;
+  font-size: clamp(1.25rem, 2.5vw, 1.5rem);
+  font-weight: 800;
+  letter-spacing: -0.02em;
+  color: white;
+  margin-top: 2rem;
+  margin-bottom: 1rem;
+  display: flex;
+  align-items: center;
+  gap: 0.625rem;
+}
+
+.sm-scope .sm-subheading-eyebrow {
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  font-size: 0.6875rem;
+  letter-spacing: 0.22em;
+  text-transform: uppercase;
+  color: #67e8f9;
+  margin-bottom: 0.35rem;
+  margin-top: 2rem;
+  display: block;
+}
+
+.sm-scope .sm-subheading + .sm-subheading-eyebrow {
+  margin-top: 1.25rem;
+}
+
+/* Anchor offset for TOC jumps */
+.sm-scope [data-anchor] {
+  scroll-margin-top: 6rem;
+}
+
 /* Range slider */
 .sm-scope .sm-range {
   -webkit-appearance: none;

